NODE_OPTIONS="--max-old-space-size=4096" npx vitest run --coverage

# Or run coverage on a subset
npx vitest run --coverage src/core/
```

If V8 provider keeps crashing, switch to Istanbul. It's slightly slower but more memory-efficient for large codebases.

When MSW handlers don't intercept requests, the app makes real network calls which either fail or return unexpected data.

```typescript
import { setupServer } from 'msw/node';
import { http, HttpResponse } from 'msw';

const server = setupServer(
  http.get('https://api.example.com/users', () => {
    return HttpResponse.json([{ id: 1, name: 'Alice' }]);
  }),
);

// Debug: log unhandled requests
beforeAll(() => {
  server.listen({
    onUnhandledRequest: (request) => {
      console.error(
        `Unhandled ${request.method} ${request.url}`,
        '\nDid you forget to add a handler?'
      );
      throw new Error(`No handler for ${request.method} ${request.url}`);
    },
  });
});

// Common causes:
// 1. URL mismatch (http vs https, trailing slash, query params)
http.get('https://api.example.com/users', ...)  // won't match http://
http.get('https://api.example.com/users/', ...) // trailing slash matters

// 2. Method mismatch
http.get('/users', ...)  // won't match POST /users

// 3. Handler not reset between tests
afterEach(() => server.resetHandlers());

// 4. Override handler for specific test
test('handles error', async () => {
  server.use(
    http.get('https://api.example.com/users', () => {
      return HttpResponse.json({ error: 'Server error' }, { status: 500 });
    }),
  );
  // This handler takes precedence for this test only
});
```

A production-ready Vitest setup with global mocks, fixtures, and cleanup.

```typescript
// test/setup.ts
import '@testing-library/jest-dom/vitest';
import { cleanup } from '@testing-library/react';
import { afterEach, beforeAll, afterAll, vi } from 'vitest';
import { setupServer } from 'msw/node';
import { handlers } from './mocks/handlers';

// MSW server
export const server = setupServer(...handlers);

beforeAll(() => {
  server.listen({ onUnhandledRequest: 'error' });
});

afterEach(() => {
  cleanup();           // unmount React components
  server.resetHandlers(); // reset MSW handlers
  vi.restoreAllMocks();   // restore spied/mocked functions
  vi.useRealTimers();     // restore real timers if faked
});

afterAll(() => {
  server.close();
});

// Mock global APIs
Object.defineProperty(window, 'matchMedia', {
  writable: true,
  value: vi.fn().mockImplementation(query => ({
    matches: false,
    media: query,
    onchange: null,
    addListener: vi.fn(),
    removeListener: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    dispatchEvent: vi.fn(),
  })),
});

// Mock IntersectionObserver
global.IntersectionObserver = vi.fn().mockImplementation(() => ({
  observe: vi.fn(),
  unobserve: vi.fn(),
  disconnect: vi.fn(),
}));

// Mock window.scrollTo
global.scrollTo = vi.fn();
```

```typescript
// vitest.config.ts
export default defineConfig({
  test: {
    globals: true,
    environment: 'jsdom',
    setupFiles: ['./test/setup.ts'],
  },
});
```

Use factory functions to create test data with sensible defaults and easy overrides.

```typescript
// test/factories.ts
import { faker } from '@faker-js/faker';

interface User {
  id: number;
  name: string;
  email: string;
  role: 'admin' | 'user';
  createdAt: Date;
}

interface Post {
  id: number;
  title: string;
  content: string;
  authorId: number;
  published: boolean;
}

let nextId = 1;

export function createUser(overrides: Partial<User> = {}): User {
  return {
    id: nextId++,
    name: faker.person.fullName(),
    email: faker.internet.email(),
    role: 'user',
    createdAt: new Date('2024-01-01'),
    ...overrides,
  };
}

export function createPost(overrides: Partial<Post> = {}): Post {
  return {
    id: nextId++,
    title: faker.lorem.sentence(),
    content: faker.lorem.paragraphs(2),
    authorId: 1,
    published: false,
    ...overrides,
  };
}

// Builders for related data
export function createUserWithPosts(userOverrides = {}, postCount = 3) {
  const user = createUser(userOverrides);
  const posts = Array.from({ length: postCount }, () =>
    createPost({ authorId: user.id })
  );
  return { user, posts };
}
```

```typescript
// Usage in tests
test('displays user profile', () => {
  const user = createUser({ name: 'Alice', role: 'admin' });
  render(<UserProfile user={user} />);
  expect(screen.getByText('Alice')).toBeInTheDocument();
  expect(screen.getByText('admin')).toBeInTheDocument();
});
```

Comprehensive MSW handler patterns covering CRUD, auth, pagination, and error scenarios.

```typescript
import { http, HttpResponse, delay } from 'msw';

const users = new Map<number, any>();
users.set(1, { id: 1, name: 'Alice', email: 'alice@test.com' });

export const handlers = [
  // GET with query params
  http.get('*/api/users', ({ request }) => {
    const url = new URL(request.url);
    const page = Number(url.searchParams.get('page') || 1);
    const limit = Number(url.searchParams.get('limit') || 10);
    const allUsers = Array.from(users.values());
    return HttpResponse.json({
      data: allUsers.slice((page - 1) * limit, page * limit),
      total: allUsers.length,
    });
  }),

  // GET by ID
  http.get('*/api/users/:id', ({ params }) => {
    const user = users.get(Number(params.id));
    if (!user) return HttpResponse.json({ error: 'Not found' }, { status: 404 });
    return HttpResponse.json(user);
  }),

  // POST with body parsing
  http.post('*/api/users', async ({ request }) => {
    const body = await request.json() as any;
    const newUser = { id: users.size + 1, ...body };
    users.set(newUser.id, newUser);
    return HttpResponse.json(newUser, { status: 201 });
  }),

  // Auth: check authorization header
  http.get('*/api/protected', ({ request }) => {
    const auth = request.headers.get('Authorization');
    if (!auth?.startsWith('Bearer ')) {
      return HttpResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
    return HttpResponse.json({ secret: 'data' });
  }),

  // Simulated latency
  http.get('*/api/slow', async () => {
    await delay(2000);
    return HttpResponse.json({ data: 'finally' });
  }),

  // File upload
  http.post('*/api/upload', async ({ request }) => {
    const formData = await request.formData();
    const file = formData.get('file') as File;
    return HttpResponse.json({ filename: file?.name, size: file?.size });
  }),
];
```

Complete pattern for testing components that fetch data, including loading, success, and error states.

```typescript
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { server } from '../test/setup';
import { http, HttpResponse } from 'msw';
import { UserProfile } from './UserProfile';

describe('UserProfile', () => {
  test('shows loading state then user data', async () => {
    render(<UserProfile userId={1} />);

    // Verify loading state appears
    expect(screen.getByText('Loading...')).toBeInTheDocument();

    // Wait for data to load
    await waitFor(() => {
      expect(screen.getByText('Alice')).toBeInTheDocument();
    });

    // Loading should be gone
    expect(screen.queryByText('Loading...')).not.toBeInTheDocument();
  });

  test('shows error state on API failure', async () => {
    // Override handler for this test
    server.use(
      http.get('*/api/users/:id', () => {
        return HttpResponse.json({ error: 'Server error' }, { status: 500 });
      }),
    );

    render(<UserProfile userId={1} />);

    await waitFor(() => {
      expect(screen.getByText(/error/i)).toBeInTheDocument();
    });
  });

  test('refetches on retry button click', async () => {
    const user = userEvent.setup();
    let callCount = 0;

    server.use(
      http.get('*/api/users/:id', () => {
        callCount++;
        if (callCount === 1) {
          return HttpResponse.json({ error: 'fail' }, { status: 500 });
        }
        return HttpResponse.json({ id: 1, name: 'Alice' });
      }),
    );

    render(<UserProfile userId={1} />);

    await waitFor(() => {
      expect(screen.getByText(/error/i)).toBeInTheDocument();
    });

    await user.click(screen.getByRole('button', { name: 'Retry' }));

    await waitFor(() => {
      expect(screen.getByText('Alice')).toBeInTheDocument();
    });
  });
});
