Extend Vitest's `expect` with custom matchers for cleaner, more expressive tests.

```typescript
// test/matchers.ts
import { expect } from 'vitest';

expect.extend({
  toBeValidEmail(received: string) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const pass = emailRegex.test(received);
    return {
      pass,
      message: () =>
        pass
          ? `expected "${received}" not to be a valid email`
          : `expected "${received}" to be a valid email`,
    };
  },

  toBeWithinRange(received: number, floor: number, ceiling: number) {
    const pass = received >= floor && received <= ceiling;
    return {
      pass,
      message: () =>
        `expected ${received} ${pass ? 'not ' : ''}to be within [${floor}, ${ceiling}]`,
    };
  },

  toHaveBeenCalledWithError(received: any, expectedMessage: string) {
    const calls = received.mock.calls;
    const pass = calls.some((call: any[]) =>
      call.some((arg: any) => arg instanceof Error && arg.message.includes(expectedMessage))
    );
    return {
      pass,
      message: () =>
        `expected mock ${pass ? 'not ' : ''}to have been called with Error("${expectedMessage}")`,
    };
  },
});

// Type declarations
declare module 'vitest' {
  interface Assertion<T = any> {
    toBeValidEmail(): void;
    toBeWithinRange(floor: number, ceiling: number): void;
  }
  interface AsymmetricMatchersContaining {
    toBeValidEmail(): void;
    toBeWithinRange(floor: number, ceiling: number): void;
  }
}
