A comprehensive reference for all common mocking patterns.

```typescript
import { vi, describe, test, expect } from 'vitest';

// 1. Mock entire module
vi.mock('./api', () => ({
  fetchUser: vi.fn().mockResolvedValue({ id: 1 }),
  fetchPosts: vi.fn().mockResolvedValue([]),
}));

// 2. Partial mock (keep real implementations for some exports)
vi.mock('./utils', async (importOriginal) => {
  const actual = await importOriginal<typeof import('./utils')>();
  return {
    ...actual, // keep all real implementations
    formatDate: vi.fn().mockReturnValue('2024-01-01'), // mock only this
  };
});

// 3. Mock a class
vi.mock('./services/UserService', () => {
  return {
    UserService: vi.fn().mockImplementation(() => ({
      getUser: vi.fn().mockResolvedValue({ id: 1 }),
      updateUser: vi.fn().mockResolvedValue(true),
    })),
  };
});

// 4. Spy on an existing method (no mock, just tracking)
const spy = vi.spyOn(console, 'error').mockImplementation(() => {});
test('logs error', () => {
  myFunction(); // calls console.error internally
  expect(spy).toHaveBeenCalledWith('Something went wrong');
});

// 5. Mock implementation per test
test('success case', () => {
  vi.mocked(fetchUser).mockResolvedValueOnce({ id: 1, name: 'Alice' });
  // ...
});

test('error case', () => {
  vi.mocked(fetchUser).mockRejectedValueOnce(new Error('Not found'));
  // ...
});

// 6. Mock return values in sequence
const mockRandom = vi.fn()
  .mockReturnValueOnce(0.1)
  .mockReturnValueOnce(0.5)
  .mockReturnValueOnce(0.9);
