Testing time-dependent code with Vitest's fake timer utilities.

```typescript
import { vi, test, expect, beforeEach, afterEach } from 'vitest';

beforeEach(() => {
  vi.useFakeTimers();
});

afterEach(() => {
  vi.useRealTimers();
});

// Test debounce
test('debounced search waits 300ms before executing', async () => {
  const searchFn = vi.fn();
  const debouncedSearch = debounce(searchFn, 300);

  debouncedSearch('a');
  debouncedSearch('ab');
  debouncedSearch('abc');

  expect(searchFn).not.toHaveBeenCalled(); // not yet

  await vi.advanceTimersByTimeAsync(300);

  expect(searchFn).toHaveBeenCalledOnce();
  expect(searchFn).toHaveBeenCalledWith('abc'); // only last call
});

// Test setTimeout
test('notification auto-dismisses after 5 seconds', async () => {
  const onDismiss = vi.fn();
  render(<Notification message="Hello" onDismiss={onDismiss} />);

  expect(screen.getByText('Hello')).toBeInTheDocument();
  expect(onDismiss).not.toHaveBeenCalled();

  await vi.advanceTimersByTimeAsync(5000);

  expect(onDismiss).toHaveBeenCalledOnce();
});

// Test setInterval
test('polling fetches data every 10 seconds', async () => {
  const fetchFn = vi.fn().mockResolvedValue({ data: 'ok' });
  startPolling(fetchFn, 10000);

  expect(fetchFn).toHaveBeenCalledOnce(); // initial call

  await vi.advanceTimersByTimeAsync(10000);
  expect(fetchFn).toHaveBeenCalledTimes(2);

  await vi.advanceTimersByTimeAsync(10000);
  expect(fetchFn).toHaveBeenCalledTimes(3);
});

// Test Date.now() with fake timers
test('records timestamp', () => {
  vi.setSystemTime(new Date('2024-06-15T12:00:00Z'));

  const record = createRecord();
  expect(record.createdAt).toEqual(new Date('2024-06-15T12:00:00Z'));

  vi.advanceTimersByTime(3600000); // 1 hour
  const later = createRecord();
  expect(later.createdAt).toEqual(new Date('2024-06-15T13:00:00Z'));
});
