Quick reference for converting Jest tests to Vitest with all API mappings.

```typescript
// ─── Imports ───
// Jest: globals are automatic
// Vitest: import or enable globals
import { describe, test, expect, vi, beforeEach, afterEach } from 'vitest';

// ─── Mocking ───
jest.fn()           → vi.fn()
jest.mock()         → vi.mock()
jest.spyOn()        → vi.spyOn()
jest.mocked()       → vi.mocked()
jest.clearAllMocks() → vi.clearAllMocks()
jest.resetAllMocks() → vi.resetAllMocks()
jest.restoreAllMocks() → vi.restoreAllMocks()

// ─── Timers ───
jest.useFakeTimers()  → vi.useFakeTimers()
jest.useRealTimers()  → vi.useRealTimers()
jest.advanceTimersByTime(ms) → vi.advanceTimersByTime(ms)
jest.runAllTimers()   → vi.runAllTimers()
jest.setSystemTime()  → vi.setSystemTime()

// ─── Module mocking ───
// Jest: automatic hoisting with jest.mock
jest.mock('./api');         → vi.mock('./api');
// Vitest: same hoisting behavior

// Jest: manual mock in __mocks__ directory
// Vitest: same convention works

// ─── Snapshot ───
// Same API, but regenerate snapshots:
// npx vitest run --update

// ─── Config mapping ───
// jest.config.ts → vitest.config.ts
testEnvironment: 'jsdom'    → test.environment: 'jsdom'
setupFilesAfterFramework    → test.setupFiles
transformIgnorePatterns     → (not needed, Vitest handles ESM)
moduleNameMapper            → resolve.alias
```

