Vitest supports writing tests directly in source files using `import.meta.vitest`. Tests are tree-shaken out of production builds.

```typescript
// src/utils/math.ts
export function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

export function lerp(start: number, end: number, t: number): number {
  return start + (end - start) * clamp(t, 0, 1);
}

export function roundTo(value: number, decimals: number): number {
  const factor = Math.pow(10, decimals);
  return Math.round(value * factor) / factor;
}

// In-source tests — stripped from production build
if (import.meta.vitest) {
  const { describe, test, expect } = import.meta.vitest;

  describe('clamp', () => {
    test('clamps below min', () => expect(clamp(-5, 0, 10)).toBe(0));
    test('clamps above max', () => expect(clamp(15, 0, 10)).toBe(10));
    test('returns value within range', () => expect(clamp(5, 0, 10)).toBe(5));
  });

  describe('lerp', () => {
    test('interpolates at 0', () => expect(lerp(0, 100, 0)).toBe(0));
    test('interpolates at 1', () => expect(lerp(0, 100, 1)).toBe(100));
    test('interpolates at 0.5', () => expect(lerp(0, 100, 0.5)).toBe(50));
    test('clamps t value', () => expect(lerp(0, 100, 2)).toBe(100));
  });

  describe('roundTo', () => {
    test('rounds to 2 decimals', () => expect(roundTo(3.14159, 2)).toBe(3.14));
    test('rounds to 0 decimals', () => expect(roundTo(3.7, 0)).toBe(4));
  });
}
