Patterns for testing components that depend on React context.

```typescript
import { render, screen, renderHook, act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { AuthProvider, useAuth } from './AuthContext';

// Helper: wrap with providers
function renderWithAuth(ui: React.ReactElement, authState = {}) {
  const defaultAuth = {
    user: null,
    isAuthenticated: false,
    login: vi.fn(),
    logout: vi.fn(),
    ...authState,
  };

  return render(
    <AuthProvider value={defaultAuth}>
      {ui}
    </AuthProvider>
  );
}

// Create reusable wrapper for all providers
function AllProviders({ children }: { children: React.ReactNode }) {
  return (
    <AuthProvider>
      <ThemeProvider>
        <QueryClientProvider client={queryClient}>
          {children}
        </QueryClientProvider>
      </ThemeProvider>
    </AuthProvider>
  );
}

// Custom render with all providers
function renderWithProviders(ui: React.ReactElement) {
  return render(ui, { wrapper: AllProviders });
}

// Test the context hook directly
describe('useAuth', () => {
  test('provides authentication state', () => {
    const { result } = renderHook(() => useAuth(), {
      wrapper: AuthProvider,
    });

    expect(result.current.isAuthenticated).toBe(false);
    expect(result.current.user).toBeNull();
  });

  test('login updates state', async () => {
    const { result } = renderHook(() => useAuth(), {
      wrapper: AuthProvider,
    });

    await act(async () => {
      await result.current.login('admin@test.com', 'password');
    });

    expect(result.current.isAuthenticated).toBe(true);
    expect(result.current.user).toEqual(
      expect.objectContaining({ email: 'admin@test.com' })
    );
  });
});

// Test consumer component
describe('Navigation', () => {
  test('shows login when unauthenticated', () => {
    renderWithAuth(<Navigation />, { isAuthenticated: false });
    expect(screen.getByText('Login')).toBeInTheDocument();
  });

  test('shows user menu when authenticated', () => {
    renderWithAuth(<Navigation />, {
      isAuthenticated: true,
      user: { name: 'Alice', email: 'alice@test.com' },
    });
    expect(screen.getByText('Alice')).toBeInTheDocument();
  });
});
