Test real-time WebSocket features without a running server.

```typescript
import { vi, describe, test, expect, beforeEach, afterEach } from 'vitest';

// Mock WebSocket
class MockWebSocket {
  static instances: MockWebSocket[] = [];
  readyState = WebSocket.CONNECTING;
  onopen: ((ev: Event) => void) | null = null;
  onmessage: ((ev: MessageEvent) => void) | null = null;
  onclose: ((ev: CloseEvent) => void) | null = null;
  onerror: ((ev: Event) => void) | null = null;
  sent: string[] = [];

  constructor(public url: string) {
    MockWebSocket.instances.push(this);
    setTimeout(() => {
      this.readyState = WebSocket.OPEN;
      this.onopen?.(new Event('open'));
    }, 0);
  }

  send(data: string) { this.sent.push(data); }
  close() {
    this.readyState = WebSocket.CLOSED;
    this.onclose?.(new CloseEvent('close'));
  }

  // Test helper: simulate server sending a message
  simulateMessage(data: any) {
    this.onmessage?.(new MessageEvent('message', {
      data: JSON.stringify(data),
    }));
  }
}

beforeEach(() => {
  MockWebSocket.instances = [];
  vi.stubGlobal('WebSocket', MockWebSocket);
});

afterEach(() => {
  vi.unstubAllGlobals();
});

test('connects and receives messages', async () => {
  const { result } = renderHook(() => useChat('room-1'));

  await waitFor(() => {
    expect(MockWebSocket.instances).toHaveLength(1);
  });

  const ws = MockWebSocket.instances[0];
  expect(ws.url).toContain('room-1');

  // Simulate incoming message
  act(() => {
    ws.simulateMessage({ user: 'Alice', text: 'Hello!' });
  });

  expect(result.current.messages).toHaveLength(1);
  expect(result.current.messages[0].text).toBe('Hello!');
});
