Guidelines for using snapshots effectively without creating maintenance burden.

```typescript
// GOOD: small, focused snapshots
test('renders button variants', () => {
  const { container } = render(<Button variant="primary" />);
  expect(container.firstChild).toMatchInlineSnapshot(`
    <button class="btn btn-primary">
      Click me
    </button>
  `);
});

// BAD: large component snapshots
test('renders entire page', () => {
  render(<Dashboard />);
  expect(document.body).toMatchSnapshot();
  // 500-line snapshot nobody reviews in PRs
});

// GOOD: snapshot only the important part
test('renders user card', () => {
  render(<UserCard user={mockUser} />);
  const card = screen.getByRole('article');
  expect(card).toHaveTextContent('Alice');
  expect(card).toHaveClass('user-card');
  // Explicit assertions > snapshot for behavior
});

// GOOD: use toMatchObject for data structure snapshots
test('API response shape', () => {
  const response = transformApiResponse(rawData);
  expect(response).toMatchObject({
    users: expect.arrayContaining([
      expect.objectContaining({
        id: expect.any(Number),
        name: expect.any(String),
      }),
    ]),
    meta: { page: 1, total: expect.any(Number) },
  });
});

// GOOD: use inline snapshots for short output
test('formats currency', () => {
  expect(formatCurrency(1234.5)).toMatchInlineSnapshot('"$1,234.50"');
  expect(formatCurrency(0)).toMatchInlineSnapshot('"$0.00"');
  expect(formatCurrency(-99.99)).toMatchInlineSnapshot('"-$99.99"');
});
```

Rules: prefer inline snapshots for values under 5 lines, use explicit assertions for behavior, save file snapshots for serialized output (API responses, config generation).

Test HTTP client configuration including interceptors, retry logic, and authentication.

```typescript
import { describe, test, expect, vi, beforeEach, afterEach } from 'vitest';
import { setupServer } from 'msw/node';
import { http, HttpResponse } from 'msw';
import { apiClient } from './apiClient'; // your configured axios/fetch wrapper

const server = setupServer();
beforeAll(() => server.listen());
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

describe('apiClient interceptors', () => {
  test('adds auth token to requests', async () => {
    let capturedHeaders: Headers | null = null;

    server.use(
      http.get('*/api/data', ({ request }) => {
        capturedHeaders = request.headers;
        return HttpResponse.json({ ok: true });
      }),
    );

    // Set token
    apiClient.setToken('my-jwt-token');
    await apiClient.get('/api/data');

    expect(capturedHeaders?.get('Authorization')).toBe('Bearer my-jwt-token');
  });

  test('retries on 503 with exponential backoff', async () => {
    vi.useFakeTimers();
    let attempts = 0;

    server.use(
      http.get('*/api/flaky', () => {
        attempts++;
        if (attempts < 3) {
          return HttpResponse.json({ error: 'unavailable' }, { status: 503 });
        }
        return HttpResponse.json({ data: 'success' });
      }),
    );

    const promise = apiClient.get('/api/flaky');

    // Advance through retries
    await vi.advanceTimersByTimeAsync(1000); // 1st retry
    await vi.advanceTimersByTimeAsync(2000); // 2nd retry

    const result = await promise;
    expect(result.data).toBe('success');
    expect(attempts).toBe(3);

    vi.useRealTimers();
  });

  test('refreshes token on 401 and retries', async () => {
    let callCount = 0;

    server.use(
      http.get('*/api/protected', () => {
        callCount++;
        if (callCount === 1) {
          return HttpResponse.json({ error: 'expired' }, { status: 401 });
        }
        return HttpResponse.json({ secret: 'data' });
      }),
      http.post('*/api/auth/refresh', () => {
        return HttpResponse.json({ token: 'new-token' });
      }),
    );

    const result = await apiClient.get('/api/protected');
    expect(result.secret).toBe('data');
    expect(callCount).toBe(2); // original + retry
  });
});
```

