```typescript
import { render, screen, waitFor } from '@testing-library/react';
import { renderHook } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import userEvent from '@testing-library/user-event';

// Create a fresh QueryClient for each test
function createTestQueryClient() {
  return new QueryClient({
    defaultOptions: {
      queries: {
        retry: false,         // don't retry in tests
        gcTime: 0,            // don't cache between tests
        staleTime: 0,
      },
      mutations: {
        retry: false,
      },
    },
  });
}

// Wrapper for renderHook
function createWrapper() {
  const queryClient = createTestQueryClient();
  return ({ children }: { children: React.ReactNode }) => (
    <QueryClientProvider client={queryClient}>
      {children}
    </QueryClientProvider>
  );
}

// Test a query hook
describe('useUser', () => {
  test('fetches and returns user data', async () => {
    const { result } = renderHook(() => useUser(1), {
      wrapper: createWrapper(),
    });

    expect(result.current.isLoading).toBe(true);

    await waitFor(() => {
      expect(result.current.isSuccess).toBe(true);
    });

    expect(result.current.data).toEqual(
      expect.objectContaining({ id: 1, name: 'Alice' })
    );
  });
});

// Test a component with mutations
describe('CreateUserForm', () => {
  test('creates user and shows success', async () => {
    const user = userEvent.setup();
    const queryClient = createTestQueryClient();

    render(
      <QueryClientProvider client={queryClient}>
        <CreateUserForm />
      </QueryClientProvider>
    );

    await user.type(screen.getByLabelText('Name'), 'Bob');
    await user.type(screen.getByLabelText('Email'), 'bob@test.com');
    await user.click(screen.getByRole('button', { name: 'Create' }));

    await waitFor(() => {
      expect(screen.getByText(/created successfully/i)).toBeInTheDocument();
    });
  });
});
```

The `act()` warning means a state update happened outside of React's controlled testing context. It can indicate a real bug or a missing await.

```typescript
// Warning: An update to MyComponent inside a test was not wrapped in act(...)

// Cause 1: Missing await on async operation
// BAD:
test('loads data', () => {  // not async!
  render(<DataLoader />);
  // State update from useEffect happens after test ends
});

// GOOD:
test('loads data', async () => {
  render(<DataLoader />);
  await waitFor(() => {
    expect(screen.getByText('Data loaded')).toBeInTheDocument();
  });
});

// Cause 2: Timer-based updates without advancing time
test('auto-saves', async () => {
  vi.useFakeTimers();
  render(<AutoSaveForm />);

  // Trigger the auto-save timer
  await act(async () => {
    vi.advanceTimersByTime(5000);
  });

  expect(screen.getByText('Saved')).toBeInTheDocument();
  vi.useRealTimers();
});

// Cause 3: Fire-and-forget promises in useEffect
// In your component:
useEffect(() => {
  fetchData().then(setData); // state update after unmount
  // Fix: add cleanup
  return () => { isMounted = false; };
}, []);
```

In most cases, the fix is adding `async/await` and `waitFor`. If you're using `userEvent.setup()`, its methods already handle `act()` wrapping.

This happens when your `vitest.config.ts` uses ESM imports but your project isn't configured for ESM.

```bash
# Error: SyntaxError: Cannot use import statement outside a module
# or: Error: Unknown file extension ".ts"

# Fix 1: Ensure vitest.config.ts uses proper extension
# vitest.config.ts (TypeScript — auto-handled by Vitest)
# vitest.config.mts (explicit ESM)
# vitest.config.cts (explicit CommonJS)

# Fix 2: Add "type": "module" to package.json
{
  "type": "module"
}

# Fix 3: Use .mts extension for explicit ESM
# Rename: vitest.config.ts → vitest.config.mts
```

```typescript
// If you can't use ESM, use CJS syntax:
// vitest.config.cts
const { defineConfig } = require('vitest/config');

module.exports = defineConfig({
  test: {
    globals: true,
  },
});
```

Vitest uses Vite to load its own config file. If Vite can't resolve the config's imports, you get this error. The simplest fix is usually adding `"type": "module"` to package.json.
